// instrStep0SizeCheck is the shared Step 0 size-check + decomposition recipe.
// Both variants emit it verbatim; per-variant preamble runs before it.
const instrStep0SizeCheck = `

## Step 0: size check

Too big if any holds:

- More than ~6 ACs spanning unrelated subsystems.
- AC mixes design, implementation, integration tests, and docs.
- Description names multiple feature-sized pieces.
- More than ~500 lines across ~5+ files in unrelated packages.
- If the bead description exceeds 8000 bytes, use a split-first pass.
- Auto-decomposition is capped at depth 2: root beads may split once, children once more; reject third-level splits with an explanation.

If too big, decompose:

1. ` + "`ddx bead create`" + ` for each child (copy parent's labels and spec-id).
2. ` + "`ddx bead dep add`" + ` only for legitimate child-to-child or sibling/replacement edges; never the parent.
3. Use ` + "`parent=<parent-id>`" + ` metadata and wire ` + "`parent -> child`" + `.
4. Write ` + "`no_changes_rationale.txt`" + ` under the bead metadata ` + "`bundle`" + ` path with child IDs, then stop.

Decomposition alone is success. Don't mix it with implementation.`

// instrNoChangesContract is the shared NoChangesContract (TD-031 §8.1) rule.
const instrNoChangesContract = `

## no_changes contract

The ` + "`no_changes_rationale.txt`" + ` file under the bead metadata ` + "`bundle`" + ` path must contain one of:

- ` + "`verification_command: <cmd>`" + ` — repo cwd; exit 0 closes, nonzero rejects.
- ` + "`status: open`" + ` + ` + "`reason: <retryable>`" + ` — open, smart retry.
- ` + "`status: proposed`" + ` + ` + "`reason: <operator needed>`" + ` — operator lane.
- ` + "`status: blocked`" + ` + ` + "`reason: <external blocker>`" + ` — blocked lane.

No pseudo-statuses. Bare rationales and ` + "`status: needs_investigation`" + ` are rejected.

For orchestrator decomposition, add ` + "`orchestrator_action: decompose`" + ` alongside ` + "`status: open`" + `.`

// instrInvestigationReports is the shared report-output rule.
const instrInvestigationReports = `

## Reports

Reports go under the bead metadata ` + "`bundle`" + ` path in ` + "`.ddx/executions/`" + `. **Never write reports to ` + "`/tmp`" + ` or outside the repo**. Use a named in-repo path when given; otherwise write ` + "`<short-name>.md`" + ` there. Commit it with the code.`

// instrReviewGate is the shared review-as-gate rule.
const instrReviewGate = `

## Review gate

- The review is a gate, not an escape hatch — meet every AC in this pass.
- Address every BLOCKING ` + "`<review-findings>`" + ` item; do not declare ` + "`no_changes`" + ` with blocking findings open.`

// instrBeadOverride is the shared mode + bead-overrides-defaults rule.
const instrBeadOverride = `

## Mode and overrides

DDX_MODE=bead_execution: edit code/docs for bead AC. Only broad queue-steward default is overridden; tracker, merge-policy, verification, safety stay active. Bead description/AC override CLAUDE.md, AGENTS.md, and defaults.`

// instrCoreConstraints is the shared core-constraints tail.
const instrCoreConstraints = `

## Constraints

- Work only inside this execution worktree.
- Keep ` + "`.ddx/executions/`" + ` intact — DDx uses it as execution evidence.
- **Never run ` + "`ddx init`" + `** — the workspace is initialized.
- Do not modify files outside the bead's named scope.
- Do not rewrite CLAUDE.md, AGENTS.md, or other instruction files unless the bead asks.`

// instrLongRunningMatrixGuards is the shared long-running matrix/benchmark guardrails (FEAT-010).
const instrLongRunningMatrixGuards = `

## Long-running matrix/benchmark beads

For expensive commands (benchmarks, load tests, validation > 60s per variant):

- Write a matrix plan before launching expensive commands: list required configs, output paths, completion criteria.
- Do not re-run the same long-running command unless: (1) the command fingerprint changed (args/env/config), AND (2) you document why prior output is invalid and what changed.
- If a long-running command times out or is incomplete, exit with ` + "`status: open`" + ` + retryable ` + "`reason`" + ` in ` + "`no_changes_rationale.txt`" + `. Do not silently retry; let the orchestrator decide.`

// executeBeadInstructionsClaudeText is the <instructions> body used when the
// harness carries its own rich system prompt (claude, codex, opencode,
// unknown). It composes a Claude-specific preamble + process body with the
// shared instr* blocks.
const executeBeadInstructionsClaudeText = `You are executing one bead in an isolated DDx execution worktree. The bead's <description> and <acceptance> are the contract: every AC must be provably satisfied by a specific code, test, or file after your commit.` +
	instrStep0SizeCheck +
	`

## How to work

- Read first. If the bead names files, specs, or prior beads, read them before editing — do not guess.
- Cross-reference each AC to concrete evidence (test, file, function) before committing. If you cannot point at it, it is not done.
- Run the project's test and lint commands before committing. **Do not commit red code** — fix failures first.
- Run git/index mutations sequentially; don't parallelize ` + "`git add`" + `, ` + "`git commit`" + `, or staging/commit commands.
- Stage with ` + "`git add <specific-paths>`" + `; never ` + "`git add -A`" + ` (the worktree may have unrelated WIP).
- If ` + "`lefthook run pre-commit`" + ` depends on staged files, rerun it after staging the exact commit set. A ` + "`no-staged-files`" + ` run is not acceptance evidence.
- Commit exactly once when green; subject ends with ` + "`[<bead-id>]`" + `. Stop after the commit.
- Do not modify files outside the bead's scope.
- Current-bead lifecycle is orchestrator-owned. Do not run ` + "`ddx bead update <bead-id> --claim`" + `, ` + "`ddx bead update <bead-id> --status <status>`" + `, ` + "`ddx bead update <bead-id> --unclaim`" + `, or ` + "`ddx bead close <bead-id>`" + `. Step 0 allows ` + "`ddx bead create`" + `, ` + "`ddx bead dep add`" + ` for child-to-child or sibling/replacement edges, and ` + "`ddx bead update <parent-id> --notes 'decomposed into <child-ids>'`" + `.
- If you cannot finish, write ` + "`no_changes_rationale.txt`" + ` under the bead metadata ` + "`bundle`" + ` path before exiting. No commit or rationale ⇒ DDx records ` + "`no_evidence_produced`" + `.` +
	instrNoChangesContract +
	instrInvestigationReports +
	instrBeadOverride +
	instrReviewGate +
	instrCoreConstraints +
	instrLongRunningMatrixGuards +
	`

## When the work is done

After the commit succeeds and every AC is verified, stop. Return control to the orchestrator.`

// executeBeadInstructionsAgentText is the <instructions> body used when the
// harness selector routes to the embedded Fizeau agent (agent / fiz /
// embedded). It composes an agent-specific preamble + tool-aware process
// body with the shared instr* blocks. The Agent variant carries the
// stop-after-commit runaway guard (codex catch).
const executeBeadInstructionsAgentText = `You are a coding agent executing one bead in an isolated DDx execution worktree. Tools: read, write, edit, bash, ls, grep, find. Use them, not ` + "`bash: cat`" + `, ` + "`bash: rg`" + `, or ` + "`bash: ls`" + `.

The bead's <description> and <acceptance> are the contract. Every AC must be satisfied by code here.` +
	instrStep0SizeCheck +
	`

## Process

- Read first. Read the files the bead names before editing — do not guess.
- Use ` + "`edit`" + `, ` + "`write`" + `, ` + "`read`" + `, ` + "`grep`" + `, and ` + "`ls`" + `; never the bash equivalents.
- Run the project's test and lint commands before committing. **Do not commit red code**.
- Run git/index mutations sequentially; don't parallelize ` + "`git add`" + `, ` + "`git commit`" + `, or staging/commit commands.
- Stage with ` + "`git add <specific-paths>`" + `; never ` + "`git add -A`" + `.
- If ` + "`lefthook run pre-commit`" + ` depends on staged files, rerun it after staging the exact commit set. A ` + "`no-staged-files`" + ` run is not acceptance evidence.
- Commit exactly once when green; subject ends with ` + "`[<bead-id>]`" + `.
- Stop immediately after the commit succeeds. Do not keep reading or testing.
- Do not modify files outside the bead's scope.
- Current-bead lifecycle is orchestrator-owned. Do not run ` + "`ddx bead update <bead-id> --claim`" + `, ` + "`ddx bead update <bead-id> --status <status>`" + `, ` + "`ddx bead update <bead-id> --unclaim`" + `, or ` + "`ddx bead close <bead-id>`" + `. Step 0 allows ` + "`ddx bead create`" + `, ` + "`ddx bead dep add`" + ` for child-to-child or sibling/replacement edges, and ` + "`ddx bead update <parent-id> --notes 'decomposed into <child-ids>'`" + `.
- If you cannot finish, write ` + "`no_changes_rationale.txt`" + ` under the bead metadata ` + "`bundle`" + ` path before exiting. No commit or rationale ⇒ ` + "`no_evidence_produced`" + `.` +
	instrNoChangesContract +
	instrInvestigationReports +
	instrBeadOverride +
	instrReviewGate +
	instrCoreConstraints +
	instrLongRunningMatrixGuards

// executeBeadInstructionsText selects the right instructions variant for the
// given harness. Harnesses with rich system prompts (claude, codex, opencode)
// get the terser claude variant; the embedded Fizeau harness gets the
// fuller agent variant with explicit tool names and stop-after-commit
// scaffolding.
func executeBeadInstructionsText(harness string) string {
	switch strings.ToLower(strings.TrimSpace(harness)) {
	case "agent", "fiz", "embedded":
		return executeBeadInstructionsAgentText
	default:
		return executeBeadInstructionsClaudeText
	}
}

// executeBeadMissingGoverningText is emitted inside <governing> when no
// governing references were pre-resolved for the bead. The bead description
// is the primary contract — this note only reminds the agent to treat it as
// such and to ground any unclear decisions in repository state rather than
// guessing.
const executeBeadMissingGoverningText = `No governing references were pre-resolved. The bead description above is the primary contract. If it names files, specs, or prior beads, read them first. Ground decisions in repository state; do not guess.`

func xmlEscape(s string) string {
	var buf bytes.Buffer
	_ = xml.EscapeText(&buf, []byte(s))
	return buf.String()
}

func xmlAttrEscape(s string) string {
	r := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&apos;",
		"\n", "&#10;",
		"\r", "&#13;",
		"\t", "&#9;",
	)
	return r.Replace(s)
}

func buildPrompt(workDir string, b *bead.Bead, refs []executeBeadGoverningRef, artifacts *executeBeadArtifacts, baseRev, promptOverride, harness string, contextBudget string) ([]byte, string, error) {
	if strings.TrimSpace(promptOverride) != "" {
		path := promptOverride
		if !filepath.IsAbs(path) {
			path = filepath.Join(workDir, path)
		}
		data, err := readPromptFileBounded(path)
		if err != nil {
			return nil, "", fmt.Errorf("reading prompt override %q: %w", promptOverride, err)
		}
		return data, promptOverride, nil
	}

	var sb strings.Builder
	sb.WriteString("<execute-bead>\n")

	instructions := executeBeadInstructionsText(harness) + executeBeadDynamicStep0Hints(workDir, b)
	// Keep the initial prefix stable for provider prefix caches: the shared
	// instructions render first, bead-specific hints append at the end of that
	// block, and the attempt-specific bundle path only appears later on
	// <metadata bundle="..."/>.
	fmt.Fprintf(&sb, "  <instructions>\n%s\n  </instructions>\n", xmlEscape(instructions))

	fmt.Fprintf(&sb, "  <bead id=\"%s\">\n", xmlAttrEscape(b.ID))
	fmt.Fprintf(&sb, "    <title>%s</title>\n", xmlEscape(strings.TrimSpace(b.Title)))

	desc := strings.TrimSpace(b.Description)
	if desc == "" {
		sb.WriteString("    <description/>\n")
	} else {
		fmt.Fprintf(&sb, "    <description>\n%s\n    </description>\n", xmlEscape(desc))
	}

	acc := strings.TrimSpace(b.Acceptance)
	if acc == "" {
		sb.WriteString("    <acceptance/>\n")
	} else {
		fmt.Fprintf(&sb, "    <acceptance>\n%s\n    </acceptance>\n", xmlEscape(acc))
	}

	// Bead notes carry review findings from prior iterations, escalation
	// context, or operator hints that did not fit into the description at
	// creation time. Threading them into the prompt as a distinct section
	// lets the agent act on them without the operator having to rewrite the
	// description in place on every reopen.
	if notes := strings.TrimSpace(b.Notes); notes != "" {
		fmt.Fprintf(&sb, "    <notes>\n%s\n    </notes>\n", xmlEscape(notes))
	}

	if len(b.Labels) > 0 {
		fmt.Fprintf(&sb, "    <labels>%s</labels>\n", xmlEscape(strings.Join(b.Labels, ", ")))
	} else {
		sb.WriteString("    <labels/>\n")
	}

	metaAttrs := make([]string, 0, 6)
	if b.Parent != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("parent=\"%s\"", xmlAttrEscape(b.Parent)))
	}
	if specID, _ := b.Extra["spec-id"].(string); strings.TrimSpace(specID) != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("spec-id=\"%s\"", xmlAttrEscape(strings.TrimSpace(specID))))
	}
	metaAttrs = append(metaAttrs, fmt.Sprintf("base-rev=\"%s\"", xmlAttrEscape(baseRev)))
	metaAttrs = append(metaAttrs, fmt.Sprintf("bundle=\"%s\"", xmlAttrEscape(artifacts.DirRel)))
	fmt.Fprintf(&sb, "    <metadata %s/>\n", strings.Join(metaAttrs, " "))
	sb.WriteString("  </bead>\n")

	// For minimal budget, omit full governing refs and only include bead metadata.
	// This significantly reduces prompt size for cheap-powerClass attempts on local models.
	if contextBudget == "minimal" {
		sb.WriteString("  <governing>\n    <note>No governing references.</note>\n  </governing>\n")
	} else {
		if len(refs) == 0 {
			fmt.Fprintf(&sb, "  <governing>\n    <note>%s</note>\n  </governing>\n", xmlEscape(executeBeadMissingGoverningText))
		} else {
			sb.WriteString("  <governing>\n")
			for _, ref := range refs {
				attrs := fmt.Sprintf("id=\"%s\" path=\"%s\"", xmlAttrEscape(ref.ID), xmlAttrEscape(ref.Path))
				if strings.TrimSpace(ref.Title) == "" {
					fmt.Fprintf(&sb, "    <ref %s/>\n", attrs)
				} else {
					fmt.Fprintf(&sb, "    <ref %s>%s</ref>\n", attrs, xmlEscape(strings.TrimSpace(ref.Title)))
				}
			}
			sb.WriteString("  </governing>\n")
		}
	}

	sb.WriteString("</execute-bead>\n")

	return []byte(sb.String()), "synthesized", nil
}

const executeBeadLargeDescriptionHintThreshold = 8000
const executeBeadAutoDecompositionDepthCap = 2

func executeBeadDynamicStep0Hints(workDir string, b *bead.Bead) string {
	if b == nil {
		return ""
	}

	var sb strings.Builder
	desc := strings.TrimSpace(b.Description)
	if len(desc) > executeBeadLargeDescriptionHintThreshold {
		fmt.Fprintf(&sb, "\n\n## Large description hint\n")
		fmt.Fprintf(&sb, "This bead description is %d bytes (> %d). Treat Step 0 as a split-first pass and prefer child-bead scoping before implementation.\n",
			len(desc), executeBeadLargeDescriptionHintThreshold)
	}

	depth := beadDecompositionDepth(workDir, b)
	if depth >= executeBeadAutoDecompositionDepthCap {
		fmt.Fprintf(&sb, "\n\n## Decomposition depth cap\n")
		fmt.Fprintf(&sb, "This bead is already at decomposition depth %d. Do not create another child layer; if it is still too large, reject the split with a short explanation and write no_changes_rationale.txt instead.\n",
			depth)
	}

	return sb.String()
}

func beadDecompositionDepth(workDir string, b *bead.Bead) int {
	if b == nil {
		return 0
	}

	store := bead.NewStore(ddxroot.JoinProject(workDir))
	depth := beadDecomposedChildDepth(b)
	seen := map[string]struct{}{}
	current := b
	for current != nil {
		parentID := strings.TrimSpace(current.Parent)
		if parentID == "" {
			break
		}
		if _, ok := seen[parentID]; ok {
			break
		}
		seen[parentID] = struct{}{}
		parent, err := store.Get(context.Background(), parentID)
		if err != nil || parent == nil {
			break
		}
		if beadDecomposedChildDepth(parent) == 0 {
			break
		}
		depth++
		current = parent
	}
	return depth
}

func beadDecomposedChildDepth(b *bead.Bead) int {
	if b == nil || strings.TrimSpace(b.Parent) == "" {
		return 0
	}
	for _, label := range b.Labels {
		if strings.TrimSpace(label) == "decomposed" {
			return 1
		}
	}
	return 0
}

// promptSHA returns the hex-encoded sha256 of the rendered prompt bytes.
// Used as manifest.prompt_sha so analytics can group attempts by the exact
// prompt that produced them.
func promptSHA(promptContent []byte) string {
	sum := sha256.Sum256(promptContent)
	return hex.EncodeToString(sum[:])
}

package bead

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

const (
	doctorFindingKindOversizedField       = "oversized_field"
	doctorFindingKindParentAncestorInDeps = "parent_ancestor_in_deps"
	doctorFindingKindUnparseableLine      = "unparseable_line"
)

// DoctorFinding reports a single bead doctor issue. Findings cover oversized
// field values, dependency edges that point back into the bead's parent chain,
// and line-level parse failures.
type DoctorFinding struct {
	Kind         string   `json:"kind,omitempty"`
	BeadID       string   `json:"bead_id"`
	FieldPath    string   `json:"field_path"`
	TargetID     string   `json:"target_id,omitempty"`
	DependencyID string   `json:"dependency_id,omitempty"`
	AncestorID   string   `json:"ancestor_id,omitempty"`
	ParentChain  []string `json:"parent_chain,omitempty"`
	SizeBytes    int      `json:"size_bytes,omitempty"`
	SampleHead   string   `json:"sample_head,omitempty"`
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

// Clean is true when there are no findings.
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

type doctorRow struct {
	lineNo   int
	rawLine  []byte
	raw      map[string]any
	bead     *Bead
	parseErr error
}

func loadDoctorRows(path string) ([]doctorRow, error) {
	src, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	lines := bytes.Split(src, []byte{'\n'})
	rows := make([]doctorRow, 0, len(lines))
	for i, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			continue
		}
		row := doctorRow{
			lineNo:  i + 1,
			rawLine: append([]byte(nil), line...),
		}
		if err := json.Unmarshal(trimmed, &row.raw); err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		bead, err := unmarshalBead(trimmed)
		if err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		row.bead = &bead
		rows = append(rows, row)
	}
	return rows, nil
}

// BeadDoctor scans a beads.jsonl file and returns every oversized field and
// every dependency edge that points back into the bead's parent chain.
// Lines that fail to parse are reported as a single finding with
// Kind=unparseable_line and the raw line as the sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	rows, err := loadDoctorRows(path)
	if err != nil {
		return report, err
	}

	byID := make(map[string]*Bead, len(rows))
	for _, row := range rows {
		if row.bead == nil || row.bead.ID == "" {
			continue
		}
		byID[row.bead.ID] = row.bead
	}

	for _, row := range rows {
		if row.parseErr != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				Kind:       doctorFindingKindUnparseableLine,
				BeadID:     fmt.Sprintf("line %d (unparseable)", row.lineNo),
				FieldPath:  "line",
				SizeBytes:  len(bytes.TrimSpace(row.rawLine)),
				SampleHead: firstN(string(bytes.TrimSpace(row.rawLine)), 80),
			})
			continue
		}
		if row.bead == nil {
			continue
		}
		report.Findings = append(report.Findings, oversizedFieldFindings(row.bead)...)
		report.Findings = append(report.Findings, parentAncestorDepFindings(row.bead, byID)...)
	}

	sortDoctorFindings(report.Findings)
	return report, nil
}

func oversizedFieldFindings(b *Bead) []DoctorFinding {
	findings := make([]DoctorFinding, 0, 5)
	if b == nil {
		return findings
	}
	for _, field := range []string{"description", "acceptance", "notes"} {
		if s := beadFieldString(b, field); len(s) > MaxFieldBytes {
			findings = append(findings, DoctorFinding{
				Kind:       doctorFindingKindOversizedField,
				BeadID:     b.ID,
				FieldPath:  field,
				SizeBytes:  len(s),
				SampleHead: firstN(s, 80),
			})
		}
	}
	for i, ev := range decodeBeadEvents(b.Extra["events"]) {
		for _, field := range []string{"body", "summary"} {
			if s := beadEventString(ev, field); len(s) > MaxFieldBytes {
				findings = append(findings, DoctorFinding{
					Kind:       doctorFindingKindOversizedField,
					BeadID:     b.ID,
					FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
	}
	return findings
}

func beadFieldString(b *Bead, field string) string {
	switch field {
	case "description":
		return b.Description
	case "acceptance":
		return b.Acceptance
	case "notes":
		return b.Notes
	default:
		return ""
	}
}

func beadEventString(ev BeadEvent, field string) string {
	switch field {
	case "body":
		return ev.Body
	case "summary":
		return ev.Summary
	default:
		return ""
	}
}

func parentAncestorDepFindings(b *Bead, byID map[string]*Bead) []DoctorFinding {
	if b == nil {
		return nil
	}
	chain, _ := beadParentChain(byID, b.Parent)
	if len(chain) == 0 || len(b.Dependencies) == 0 {
		return nil
	}
	ancestorSet := make(map[string]struct{}, len(chain))
	for _, ancestorID := range chain {
		ancestorSet[ancestorID] = struct{}{}
	}

	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		if _, ok := ancestorSet[dep.DependsOnID]; !ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindParentAncestorInDeps,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     dep.DependsOnID,
			DependencyID: dep.DependsOnID,
			AncestorID:   dep.DependsOnID,
			ParentChain:  append([]string(nil), chain...),
			SampleHead:   strings.Join(chain, " -> "),
		})
	}
	return findings
}

func sortDoctorFindings(findings []DoctorFinding) {
	sort.SliceStable(findings, func(i, j int) bool {
		if findings[i].BeadID != findings[j].BeadID {
			return findings[i].BeadID < findings[j].BeadID
		}
		if doctorFindingKindRank(findings[i].Kind) != doctorFindingKindRank(findings[j].Kind) {
			return doctorFindingKindRank(findings[i].Kind) < doctorFindingKindRank(findings[j].Kind)
		}
		if findings[i].AncestorID != findings[j].AncestorID {
			return findings[i].AncestorID < findings[j].AncestorID
		}
		if findings[i].DependencyID != findings[j].DependencyID {
			return findings[i].DependencyID < findings[j].DependencyID
		}
		if findings[i].FieldPath != findings[j].FieldPath {
			return findings[i].FieldPath < findings[j].FieldPath
		}
		if findings[i].TargetID != findings[j].TargetID {
			return findings[i].TargetID < findings[j].TargetID
		}
		return findings[i].SampleHead < findings[j].SampleHead
	})
}

func doctorFindingKindRank(kind string) int {
	switch kind {
	case doctorFindingKindOversizedField:
		return 0
	case doctorFindingKindParentAncestorInDeps:
		return 1
	case doctorFindingKindUnparseableLine:
		return 2
	default:
		return 9
	}
}

// BeadDoctorFix rewrites oversized fields on disk and removes dependency edges
// that point back into the bead's parent chain.
//
//  1. If the file is already clean, returns the empty report without
//     touching anything.
//  2. Otherwise writes a timestamped backup under .ddx/backups/ before any
//     mutation; errors if the backup write fails.
//  3. Truncates oversized fields via capFieldBytes (head+tail+marker), then
//     writes full overflow content to

package cmd

import (
	"encoding/json"
	"fmt"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/spf13/cobra"
)

// newBeadDoctorCommand wires `ddx bead doctor` / `ddx bead doctor --fix`.
//
// Scan mode (no flags): exits non-zero if any field on any bead exceeds the
// per-field cap (ddx-f8a11202) or if a dependency points back into the bead's
// parent chain. Safe to run on any tree — no mutations.
//
// Fix mode (--fix): rewrites oversized fields in place and removes dependency
// edges that point back into the bead's parent chain. Before touching the
// tracker the command writes a timestamped backup under .ddx/backups/ so
// the original file is always recoverable. Overflow content persists as
// artifacts under .ddx/executions/<bead-id>/repair-<timestamp>/ and a
// repair event is appended to each rewritten bead. Idempotent — the second
// invocation exits 0 without writing because the scan is clean.
//
// Dangling-success mode (--dangling): detects in_progress beads whose last
// execution produced task_succeeded but CloseWithEvidence never ran. Safe
// to run on any tree — no mutations unless --fix is also passed.
// (ddx-2b2d114e)
func (f *CommandFactory) newBeadDoctorCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "doctor",
		Short: "Detect (and optionally repair) beads.jsonl rows with oversized fields or back-edge deps",
		Long: `Scan the bead tracker for fields that exceed the per-field size cap.

Bead fields (description, acceptance, notes, events[].body, events[].summary)
are capped at 65,535 bytes so DDx-authored beads round-trip cleanly through
bd import (upstream's Dolt TEXT column limit). Fields over the cap usually
come from a writer bug that landed before the cap was enforced — for
example a reviewer stream dumped verbatim into an event body.

The doctor also scans for dependency edges whose targets appear in the bead's
parent chain. Those findings are reported as parent_ancestor_in_deps and
--fix removes only the offending edges, leaving the rest of the dependency
list untouched.

Without --fix this command only reports offending rows and exits non-zero.
With --fix it:

  1. Writes a timestamped backup to .ddx/backups/ before any mutation.
  2. Truncates each oversized field to the cap using head+tail+marker.
  3. Writes the full original payload for truncated fields to
     .ddx/executions/<bead>/repair-<timestamp>/<field>.log so forensics
     remain possible.
  4. Removes dependency edges that point back into the bead's parent chain.
  5. Appends a kind=repair event to every rewritten bead.

Idempotent: once a tracker is clean, running --fix again is a no-op.

With --dangling: scan for in_progress beads whose last execution produced
task_succeeded but whose bead-close step never ran (dangling-success).
For each finding, reports whether result_rev is reachable from HEAD:
  - reachable=true:  merge succeeded, close didn't. Safe to close manually
    with: ddx bead close <bead-id>
  - reachable=false: the merge itself was never applied (dangling commit).
    The result_rev is shown for manual git cherry-pick or re-attempt.
(ddx-2b2d114e)`,
		RunE: func(cmd *cobra.Command, args []string) error {
			workspace := f.beadWorkspaceRoot()
			if workspace == "" {
				return fmt.Errorf("bead doctor: no .ddx workspace found")
			}
			path := ddxroot.JoinProject(workspace, "beads.jsonl")

			doFix, _ := cmd.Flags().GetBool("fix")
			asJSON, _ := cmd.Flags().GetBool("json")
			doDangling, _ := cmd.Flags().GetBool("dangling")

			// --dangling mode: detect dangling-success beads (ddx-2b2d114e).
			if doDangling {
				findings, err := agent.DetectDanglingSuccessBeads(workspace)
				if err != nil {
					return fmt.Errorf("bead doctor --dangling: %w", err)
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(struct {
						Clean    bool                           `json:"clean"`
						Findings []agent.DanglingSuccessFinding `json:"findings"`
					}{
						Clean:    len(findings) == 0,
						Findings: findings,
					})
				}
				out := cmd.OutOrStdout()
				if len(findings) == 0 {
					fmt.Fprintf(out, "bead doctor --dangling: clean (no dangling-success beads detected)\n")
					return nil
				}
				fmt.Fprintf(out, "bead doctor --dangling: %d finding(s):\n", len(findings))
				for _, fi := range findings {
					reachableStr := "reachable=false (dangling commit — merge never applied)"
					recovery := "  recovery: git cherry-pick or re-run ddx try " + fi.BeadID
					if fi.Reachable {
						reachableStr = "reachable=true (merge succeeded, close didn't run)"
						recovery = "  recovery: ddx bead close " + fi.BeadID + "  # or re-run ddx try"
					}
					fmt.Fprintf(out, "  %s  attempt=%s  result_rev=%s\n    %s\n%s\n",
						fi.BeadID, fi.AttemptID, fi.ResultRev, reachableStr, recovery)
				}
				return fmt.Errorf("bead doctor --dangling: %d finding(s) detected", len(findings))
			}

			var report bead.DoctorReport
			var err error
			if doFix {
				report, err = bead.BeadDoctorFix(path, nil)
			} else {
				report, err = bead.BeadDoctor(path)
			}
			if err != nil {
				return err
			}

			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(struct {
					Path     string               `json:"path"`
					Fixed    bool                 `json:"fixed"`
					Clean    bool                 `json:"clean"`
					Findings []bead.DoctorFinding `json:"findings"`
				}{
					Path:     report.Path,
					Fixed:    doFix && !report.Clean(),
					Clean:    report.Clean(),
					Findings: report.Findings,
				})
			}

			out := cmd.OutOrStdout()
			if report.Clean() {
				fmt.Fprintf(out, "bead doctor: %s — clean (no oversized fields or parent-ancestor deps detected)\n", path)
				return nil
			}
			fmt.Fprintf(out, "bead doctor: %s — %d finding(s):\n", path, len(report.Findings))
			for _, f := range report.Findings {
				fmt.Fprintln(out, formatBeadDoctorFinding(f))
			}
			if doFix {
				fmt.Fprintf(out, "\nrepair complete. backup written to %s/backups/.\n", filepath.Dir(path))
				if hasBeadDoctorKind(report.Findings, "oversized_field") {
					fmt.Fprintf(out, "truncated fields were captured under %s/executions/<bead>/repair-*/\n", filepath.Dir(path))
				}
				return nil
			}
			// Non-fix scan: non-zero exit via cobra error so CI can catch it.
			return fmt.Errorf("bead doctor: %d finding(s) — run `ddx bead doctor --fix` to repair", len(report.Findings))
		},
	}
	cmd.Flags().Bool("fix", false, "Rewrite oversized fields in place after writing a backup")
	cmd.Flags().Bool("json", false, "Output findings as JSON")
	cmd.Flags().Bool("dangling", false, "Detect in_progress beads with a prior task_succeeded result (dangling-success, ddx-2b2d114e)")
	return cmd
}

func formatBeadDoctorFinding(f bead.DoctorFinding) string {
	switch f.Kind {
	case "parent_ancestor_in_deps":
		chain := f.SampleHead
		if len(f.ParentChain) > 0 {
			chain = strings.Join(f.ParentChain, " -> ")
		}
		return fmt.Sprintf("  %s  %s  %s  dependency=%s  ancestor=%s  chain=%s", f.BeadID, f.Kind, f.FieldPath, f.DependencyID, f.AncestorID, chain)
	case "unparseable_line":
		return fmt.Sprintf("  %s  %s  size=%d  head=%q", f.BeadID, f.Kind, f.SizeBytes, f.SampleHead)
	default:
		return fmt.Sprintf("  %s  %s  %s  %d bytes  head=%q", f.BeadID, f.Kind, f.FieldPath, f.SizeBytes, f.SampleHead)
	}
}

func hasBeadDoctorKind(findings []bead.DoctorFinding, kind string) bool {
	for _, f := range findings {
		if f.Kind == kind {
			return true
		}
	}
	return false
}

