				Status:    ExecuteBeadStatusExecutionFailed + "_" + ReviewTerminalClassTooLarge,
				Detail:    escalation.PerBeadBudgetExhaustedReason + ": $1.00 billed >= $0.50 per-bead budget",
				SessionID: "sess-decompose-toolarge",
